import sys
from typing import List

class Solution:
    def makeConnected(self, n: int, edges: List[List[int]]) -> int:
        if len(edges) < n - 1:
            return n - 1 - len(edges)

        parent = list(range(n))

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            root_x = find(x)
            root_y = find(y)
            if root_x != root_y:
                parent[root_x] = root_y

        for u, v in edges:
            union(u, v)

        components = set()
        for i in range(n):
            components.add(find(i))

        return len(components) - 1

