#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int makeConnected(int n, vector<vector<int>>& edges) {
        if (edges.size() < n - 1) {
            return n - 1 - edges.size();
        }

        vector<int> parent(n);
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }

        function<int(int)> find = [&](int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        };

        function<void(int, int)> union_ = [&](int x, int y) {
            int root_x = find(x);
            int root_y = find(y);
            if (root_x != root_y) {
                parent[root_x] = root_y;
            }
        };

        for (auto& edge : edges) {
            union_(edge[0], edge[1]);
        }

        unordered_set<int> components;
        for (int i = 0; i < n; i++) {
            components.insert(find(i));
        }

        return components.size() - 1;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    int e;
    if (!(cin >> e)) return 0;
    vector<vector<int>> edges(e, vector<int>(2));
    for (int i = 0; i < e; i++) {
        cin >> edges[i][0] >> edges[i][1];
    }
    Solution sol;
    int ans = sol.makeConnected(n, edges);
    cout << ans << '\n';
    return 0;
}
